import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from 'src/app/core/services/auth.service';
import { RequestorService } from 'src/app/core/services/requestor.service';
import { SponsorshipRequest, SubmitDto } from 'src/app/shared/models/request.model';

@Component({
  selector: 'app-my-requests',
  templateUrl: './my-requests.component.html',
  styleUrls: ['./my-requests.component.css']
})
export class MyRequestsComponent implements OnInit {
  requests: SponsorshipRequest[] = [];
  userId: number = 0;
  isLoading = false;
  isSubmitting = false;
  filterStatus: string = 'all';

  constructor(private authService: AuthService, private requestorService: RequestorService, private router: Router) {

  }

  ngOnInit() {
    this.userId = this.authService.getCurrentUserId();
    this.loadMyRequests();
  }

  loadMyRequests() {
    this.isLoading = true;
    this.requestorService.getMyRequests(this.userId).subscribe({
      next: (requests) => {
        this.requests = requests.map(request => {
          if (typeof request.status === 'number') {
            request.status = this.mapStatusToString(request.status);
          }
          return request;
        });
        this.isLoading = false;
      },
      error: (error) => {
        console.error('Error:', error);
        this.isLoading = false;
      }
    });
  }

  mapStatusToString(status: number): string {
    const statusMap: { [key: number]: string } = {
      1: 'Draft',
      2: 'PendingManager',
      3: 'PendingFinance',
      4: 'Approved',
      5: 'Rejected',
      6: 'Cancelled'
    };
    return statusMap[status] || 'Draft';
  }

  get filteredRequests(): SponsorshipRequest[] {
    if (this.filterStatus === 'all') {
      return this.requests;
    }
    return this.requests.filter(r => r.status === this.filterStatus);
  }

  viewDetails(id: number) {
    this.router.navigate(['/requestor/detail', id]);
  }

  submitRequest(id: number, userId: number) {
    const submitData = new SubmitDto({
      requestId: id,
      userId: userId
    });

    if (confirm('Are you sure you want to submit this request for approval?')) {
      this.isSubmitting = true;
      this.requestorService.submitRequest(submitData).subscribe({
        next: () => {
          this.isSubmitting = false;
          alert('Request submitted successfully!');
          this.router.navigate(['/requestor/my-requests']);
        },
        error: (error) => {
          this.isSubmitting = false;
          alert(error.error?.message || 'Error submitting request');
        }
      });
    }
  }

  editRequest(id: number) {
    this.router.navigate(['/requestor/edit', id]);
  }

  cancelRequest(id: number) {
    if (confirm('Are you sure you want to cancel this request?')) {
      this.requestorService.cancelRequest(id).subscribe({
        next: () => {
          alert('Request cancelled successfully');
          this.loadMyRequests();
        },
        error: (error) => {
          alert(error.error?.message || 'Error cancelling request');
        }
      });
    }
  }

  getStatusClass(status: string): string {
    switch (status) {
      case 'Draft': return 'badge-secondary';
      case 'PendingManager': return 'badge-warning';
      case 'PendingFinance': return 'badge-info';
      case 'Approved': return 'badge-success';
      case 'Rejected': return 'badge-danger';
      case 'Cancelled': return 'badge-danger';
      default: return 'badge-light';
    }
  }

  getStatusText(status: string): string {
    switch (status) {
      case 'Draft': return 'Draft';
      case 'PendingManager': return 'Pending Manager';
      case 'PendingFinance': return 'Pending Finance';
      case 'Approved': return 'Approved';
      case 'Rejected': return 'Rejected';
      case 'Cancelled': return 'Cancelled';
      default: return status;
    }
  }
}
<div class="my-requests-container">
  <!-- Page Header -->
  <div class="page-header">
    <h2>
      <i class="fas fa-list-alt"></i>
      My Sponsorship Requests
    </h2>
    <p>View and manage all your sponsorship requests</p>
  </div>

  <!-- Filters and Actions -->
  <div class="filter-bar">
    <div class="filter-group">
      <label>Filter by Status:</label>
      <select [(ngModel)]="filterStatus" class="form-control">
        <option value="all">All Requests</option>
        <option value="Draft">Draft</option>
        <option value="PendingManager">Pending Manager</option>
        <option value="PendingFinance">Pending Finance</option>
        <option value="Approved">Approved</option>
        <option value="Rejected">Rejected</option>
      </select>
    </div>

    <button class="btn-create" routerLink="/requestor/create">
      <i class="fas fa-plus"></i> Create New Request
    </button>
  </div>

  <!-- Loading Spinner -->
  <div class="loading-spinner" *ngIf="isLoading">
    <i class="fas fa-spinner fa-spin"></i>
    <p>Loading requests...</p>
  </div>

  <!-- No Requests -->
  <div class="no-data" *ngIf="!isLoading && filteredRequests.length === 0">
    <i class="fas fa-inbox"></i>
    <h3>No Requests Found</h3>
    <p>You haven't created any sponsorship requests yet.</p>
    <button class="btn-create" routerLink="/requestor/create">
      <i class="fas fa-plus"></i> Create Your First Request
    </button>
  </div>

  <!-- Requests Table -->
  <div class="table-responsive" *ngIf="!isLoading && filteredRequests.length > 0">
    <table class="requests-table">
      <thead>
        <tr>
          <th>Request ID</th>
          <th>Title</th>
          <th>Event Name</th>
          <th>Amount</th>
          <th>Status</th>
          <th>Created Date</th>
          <th>Actions</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let request of filteredRequests">
          <td>#{{ request.id }}</td>
          <td class="title-cell">{{ request.title }}</td>
          <td>{{ request.eventName }}</td>
          <td class="amount">${{ request.requestedAmount | number }}</td>
          <td>
            <span class="badge" [class]="getStatusClass(request.status)">
              {{ getStatusText(request.status) }}
            </span>
          </td>
          <td>{{ request.createdAt | date:'dd/MM/yyyy' }}</td>
          <td class="action-buttons">
            <button class="btn-view" (click)="viewDetails(request.id)" title="View Details">
              <i class="fas fa-eye"></i>
            </button>
            <button class="btn-submit" (click)="submitRequest(request.id, request.requestorId)" title="Submit" *ngIf="request.status === 'Draft'">
              <i class="fas fa-submit"></i>
            </button>
            <button class="btn-edit" (click)="editRequest(request.id)" title="Edit" *ngIf="request.status === 'Draft'">
              <i class="fas fa-edit"></i>
            </button>
            <button class="btn-cancel" (click)="cancelRequest(request.id)" title="Cancel" *ngIf="request.status === 'Draft' || request.status === 'PendingManager'">
              <i class="fas fa-times"></i>
            </button>
          </td>
      </tbody>
    </table>
  </div>
</div>
